# Python Lambda function example
# This function demonstrates how a Lambda function might interact with these services.
# It assumes the Lambda function is configured to use the shared IAM role defined above.

import json
import os
import boto3

# Initialize AWS clients
s3 = boto3.client('s3')
dynamodb = boto3.resource('dynamodb')
sns = boto3.client('sns')
sqs = boto3.client('sqs')

# Environment variables (replace with your actual resource names/ARNs)
S3_BUCKET_NAME = os.environ.get('S3_BUCKET_NAME', 'your-app-bucket')
DYNAMODB_TABLE_NAME = os.environ.get('DYNAMODB_TABLE_NAME', 'your-app-table')
SNS_TOPIC_ARN = os.environ.get('SNS_TOPIC_ARN', 'arn:aws:sns:us-east-1:123456789012:your-app-topic') # Example ARN, update region/account
SQS_QUEUE_URL = os.environ.get('SQS_QUEUE_URL', 'https://sqs.us-east-1.amazonaws.com/123456789012/your-app-queue') # Example URL, update region/account

def lambda_handler(event, context):
    """
    Main Lambda function handler.
    Demonstrates interactions with S3, DynamoDB, SNS, and SQS.
    """
    try:
        # 1. S3 Interaction: Upload a file
        s3_key = 'data/example.txt'
        s3_content = 'Hello from Lambda!'
        s3.put_object(Bucket=S3_BUCKET_NAME, Key=s3_key, Body=s3_content)
        print(f"Successfully uploaded '{s3_key}' to S3 bucket '{S3_BUCKET_NAME}'")

        # 2. DynamoDB Interaction: Put an item
        table = dynamodb.Table(DYNAMODB_TABLE_NAME)
        item_id = '123'
        table.put_item(
            Item={
                'id': item_id,
                'message': 'Data stored by Lambda',
                'timestamp': boto3.util.current_time_millis()
            }
        )
        print(f"Successfully put item with id '{item_id}' into DynamoDB table '{DYNAMODB_TABLE_NAME}'")

        # 3. SNS Interaction: Publish a message
        sns_message = {
            'source': 'lambda-function',
            'event_type': 'data_processed',
            'details': 'S3 object uploaded and DB item created.'
        }
        sns.publish(
            TopicArn=SNS_TOPIC_ARN,
            Message=json.dumps(sns_message),
            Subject='Lambda Activity Alert'
        )
        print(f"Successfully published message to SNS topic '{SNS_TOPIC_ARN}'")

        # 4. SQS Interaction: Send a message
        sqs_message_body = {
            'task_id': 'abc-123',
            'operation': 'process_file',
            'file_location': f's3://{S3_BUCKET_NAME}/{s3_key}'
        }
        sqs.send_message(
            QueueUrl=SQS_QUEUE_URL,
            MessageBody=json.dumps(sqs_message_body)
        )
        print(f"Successfully sent message to SQS queue '{SQS_QUEUE_URL}'")

        return {
            'statusCode': 200,
            'body': json.dumps('Lambda function executed successfully with service interactions.')
        }

    except Exception as e:
        print(f"Error: {e}")
        return {
            'statusCode': 500,
            'body': json.dumps(f'Error processing request: {str(e)}')
        }